import { createBrowserRouter, createHashRouter } from 'react-router-dom';
import App from '@/App'
import Login from '@/pages/user/login'
import Register from '@/pages/user/register'
import Personal from '@/pages/user/personal'
import Modify from '@/pages/user/personal/modify'
import Info from '@/pages/user/personal/info'
import Posts from '@/pages/user/personal/posts'

const router = createHashRouter([
  // const router = createBrowserRouter([
  {
    path: '/',
    element: <App />,
  },
  {
    path: '/login',
    element: <Login />,
  },
  {
    path: '/register',
    element: <Register />,
  },
  {
    path: '/personal',
    element: <Personal />,
    children: [
      {
        index: true,
        path: 'info',
        element: <Info />,
      },
      {
        path: 'posts',
        element: <Posts />,
      },
      {
        path: 'modify',
        element: <Modify />,
      },
    ]
  },
]);

export default router;
