import { request } from '@/utils/request';
import { setAccess, setRefresh } from '@/store/modules/user';

const fetchLogin = (loginForm) => {
  return async (dispatch) => {
    const res = await request.post('/user/login', loginForm);
    if (res.status === 200) {
      dispatch(setAccess(res.data.access));
      dispatch(setRefresh(res.data.refresh));
    }
  }
}

const fetchRegister = async (registerForm) => {
  const res = await request.post('/user/register', registerForm);
  console.log(res);
}

const fetchModify = async (modifyForm) => {
  const res = await request.post('/user/change-password', modifyForm);
  console.log(res);
}

export { fetchLogin, fetchRegister, fetchModify };