import React from 'react';
import { Dropdown, Layout, Avatar } from 'antd';
import { UserOutlined, MessageOutlined, LogoutOutlined } from '@ant-design/icons';
import logo from '@/assets/logo.png'
import { Link } from 'react-router-dom';
import './index.scss';

const { Header } = Layout;

const dropdownItems = [
  {
    key: '1',
    label: (
      <Link to="/personal">
        <UserOutlined /> 个人中心
      </Link>
    ),
  },
  {
    key: '2',
    label: (
      <Link to="/personal">
        <MessageOutlined /> 通知消息
      </Link>
    ),
  },
  { type: 'divider', },
  {
    key: '3',
    danger: true,
    label: (
      <Link to="/login">
        <LogoutOutlined /> 退出登录
      </Link>
    ),
  },
];

const MainHeader = () => {
  return (
    <Header>
      <div className="demo-logo">
        <Link to="/">
          <img src={logo} alt="" height={64} />
        </Link>
      </div>
      <div className="app-avatar" >
        <Dropdown menu={{ items: dropdownItems }} placement="bottomRight" arrow={{ pointAtCenter: true }}>
          <Avatar size='large' icon={<UserOutlined />} />
        </Dropdown>
      </div>
    </Header>
  )
}

export default MainHeader;
