import React from 'react';
import {
  Button,
  Form,
  Input,
  Card,
} from 'antd';
import { fetchRegister } from '@/apis/user';
import { useNavigate, Link } from 'react-router-dom';
import logo from '@/assets/logo.png';
import './index.scss';
const formItemLayout = {
  labelCol: {
    xs: { span: 24 },
    sm: { span: 6 },
  },
  wrapperCol: {
    xs: { span: 24 },
    sm: { span: 16 },
  },
};
const tailFormItemLayout = {
  wrapperCol: {
    xs: {
      span: 24,
      offset: 0,
    },
    sm: {
      span: 16,
      offset: 10,
    },
  },
};
const Register = () => {
  const navigate = useNavigate();
  const [form] = Form.useForm();
  const onFinish = values => {
    console.log('Received values of form: ', values);
    fetchRegister(values);
    navigate('/login');
  };
  return (
    <div className='register'>
      <div className="demo-logo">
        <Link to="/">
          <img src={logo} alt="" height={64} />
        </Link>
      </div>
      <Card title="注册账号" variant="borderless" style={{ width: '25%', minWidth: 320 }}>
        {/* <Flex justify="center"> */}
        <Form
          {...formItemLayout}
          form={form}
          name="register"
          onFinish={onFinish}
          style={{ maxWidth: 600 }}
          scrollToFirstError
        >
          <Form.Item
            name="email"
            label="邮箱"
            rules={[
              {
                type: 'email',
                message: '请输入正确的邮箱格式!',
              },
              {
                required: true,
                message: '请输入邮箱!',
              },
            ]}
          >
            <Input />
          </Form.Item>

          <Form.Item
            name="password"
            label="密码"
            rules={[
              {
                required: true,
                message: '请输入密码!',
              },
            ]}
            hasFeedback
          >
            <Input.Password />
          </Form.Item>

          <Form.Item
            name="confirm"
            label="确认密码"
            dependencies={['password']}
            hasFeedback
            rules={[
              {
                required: true,
                message: '请确认密码!',
              },
              ({ getFieldValue }) => ({
                validator(_, value) {
                  if (!value || getFieldValue('password') === value) {
                    return Promise.resolve();
                  }
                  return Promise.reject(new Error('两次密码不一致，请重新输入!'));
                },
              }),
            ]}
          >
            <Input.Password />
          </Form.Item>

          <Form.Item
            name="username"
            label="用户名"
            rules={[{ required: true, message: '请输入用户名!', whitespace: true }]}
          >
            <Input />
          </Form.Item>

          <Form.Item
            name="nickname"
            label="昵称"
            tooltip="请输入您希望他人称呼您为的昵称，可选，不填则默认为用户名。"
          >
            <Input />
          </Form.Item>

          {/* <Form.Item label="验证码">
              <Row gutter={8}>
                <Col span={12}>
                  <Form.Item
                    name="captcha"
                    noStyle
                    rules={[{ required: true, message: '请输入验证码!' }]}
                  >
                    <Input />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Button>获取验证码</Button>
                </Col>
              </Row>
            </Form.Item> */}

          {/* <Form.Item
              name="agreement"
              valuePropName="checked"
              rules={[
                {
                  validator: (_, value) =>
                    value ? Promise.resolve() : Promise.reject(new Error('请同意协议!')),
                },
              ]}
              {...tailFormItemLayout}
            >
              <Checkbox>
                <a href="">协议</a>
              </Checkbox>
            </Form.Item> */}
          <Form.Item {...tailFormItemLayout}>
            <Button type="primary" htmlType="submit">
              注册账号
            </Button>
          </Form.Item>
        </Form>
        {/* </Flex> */}
      </Card>
    </div>
  );
};
export default Register;
