import React, { useState, useEffect } from 'react';
import { Button, Form, Input, Layout, Descriptions, Modal, Radio, Avatar } from 'antd';
import { ArrowLeftOutlined, UserOutlined } from '@ant-design/icons';
import { useNavigate } from 'react-router-dom';
import './index.scss';

const { Header, Content } = Layout;

const items = [
  {
    key: '1',
    label: '头像',
    children:
      <>
        <div className='ant-descriptions-item-content-left'>
          <Avatar size='large' icon={<UserOutlined />} />
        </div>
        <div className='ant-descriptions-item-content-right'>
          <Button type="link">修改头像</Button>
        </div>
      </>,
  },
  {
    key: '2',
    label: '用户名',
    children: 'test',
  },
  {
    key: '3',
    label: '昵称',
    children: <>
      <div className='ant-descriptions-item-content-left'>
        test
      </div>
      <div className='ant-descriptions-item-content-right'>
        <Button type="link">修改昵称</Button>
      </div>
    </>,
  },
  {
    key: '4',
    label: '性别',
    children: <>
      <div className='ant-descriptions-item-content-left'>
        未设置
      </div>
      <div className='ant-descriptions-item-content-right'>
        <Button type="link">修改性别</Button>
      </div>
    </>,
  },
  {
    key: '5',
    label: '邮箱',
    children: 'test@example.com',
  },
  {
    key: '6',
    label: 'uid',
    children: 'test',
  },
];

const Info = () => {
  const navigate = useNavigate();
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 480);
  const [form] = Form.useForm();
  const [formValues, setFormValues] = useState();
  const [open, setOpen] = useState(false);
  const onCreate = values => {
    console.log('Received values of form: ', values);
    setFormValues(values);
    setOpen(false);
  };

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 480);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const onFinish = async values => {
    console.log('Received values of form: ', values);
  };
  return (
    <div className='info'>
      {isMobile ?
        <Header>
          <Button
            type="text"
            icon={<ArrowLeftOutlined />}
            onClick={() => navigate('/personal')}
            className="back-button"
          >
            返回
          </Button>
        </Header> : null}
      <Content>
        <Descriptions
          title="个人资料"
          bordered
          items={items}
          column={1}
          extra={<Button type="primary" onClick={() => setOpen(true)}>
            一键编辑
          </Button>} />
      </Content>
      <pre>{JSON.stringify(formValues, null, 2)}</pre>
      <Modal
        open={open}
        title="编辑资料"
        okText="确认"
        cancelText="取消"
        okButtonProps={{ autoFocus: true, htmlType: 'submit' }}
        onCancel={() => setOpen(false)}
        destroyOnHidden
        modalRender={dom => (
          <Form
            layout="vertical"
            form={form}
            name="form_in_modal"
            initialValues={{ title: 'test', avatar: 'test', gender: 'other' }}
            clearOnDestroy
            onFinish={values => onCreate(values)}
          >
            {dom}
          </Form>
        )}
      >
        <Form.Item
          name="title"
          label="昵称"
        >
          <Input />
        </Form.Item>
        <Form.Item name="avatar" label="头像">
          <Input />
        </Form.Item>
        <Form.Item name="gender" className="collection-create-form_last-form-item">
          <Radio.Group>
            <Radio value="male">男·</Radio>
            <Radio value="female">女</Radio>
            <Radio value="other">不愿透露</Radio>
          </Radio.Group>
        </Form.Item>
      </Modal>
    </div>
  );
};

export default Info;